SELECT *
FROM highlights
WHERE user_id = #{userId}
AND book_id = #{bookId}
AND page = #{page}

SELECT *
FROM highlights
WHERE user_id = #{userId}
AND book_id = #{bookId}
ORDER BY chapter_number, created_at DESC

SELECT *
FROM highlights
WHERE user_id = #{userId}
AND book_id = #{bookId}
AND chapter_number = #{chapterNumber}
ORDER BY created_at DESC

SELECT COUNT(*)
FROM highlights
WHERE user_id = #{userId}
